share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf:text='> Desencriptando flujo IPTV en vivo en tiempo real...':enable='gte(t,12.8)':fontcolor=0x00FF00:fontsize=36:x=100:y=740,drawtext=fontfile=/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf:text='[ ACTIVE ]':enable='gte(t,12.8)':fontcolor=0x00FF00:fontsize=36:x=1200:y=740[v];[1:a]volume='between(t,1.0,1.05) + between(t,2.0,2.05) + between(t,2.5,2.55) + between(t,3.5,3.55) + between(t,4.0,4.05) + between(t,5.0,5.05) + between(t,5.5,5.55) + between(t,7.0,7.05) + between(t,7.5,7.55) + between(t,8.8,8.85) + between(t,9.2,9.25) + between(t,10.5,10.55) + between(t,11.0,11.05) + between(t,12.2,12.25) + between(t,12.8,12.85)':eval=frame[a]" \
